// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

contract CoreBlackBox {
    // Estrutura para armazenar o registro de prova
    struct ProofRecord {
        string dataHash;     // O hash do documento ou dado
        address owner;       // Quem registrou
        uint256 timestamp;   // Data e hora do registro
    }

    // Mapeamento para armazenar registros por um ID ou Hash
    mapping(string => ProofRecord) public records;

    // Evento para facilitar a busca em exploradores (Etherscan)
    event NewRecord(string indexed dataHash, address indexed owner, uint256 timestamp);

    // Função para registrar um dado
    function registerData(string memory _dataHash) public {
        require(bytes(_dataHash).length > 0, "O dado nao pode estar vazio");
        
        // Armazena no blockchain
        records[_dataHash] = ProofRecord({
            dataHash: _dataHash,
            owner: msg.sender,
            timestamp: block.timestamp
        });

        // Emite o evento para rastreabilidade
        emit NewRecord(_dataHash, msg.sender, block.timestamp);
    }

    // Função para verificar se um dado existe e quem o registrou
    function verifyData(string memory _dataHash) public view returns (address, uint256) {
        require(records[_dataHash].owner != address(0), "Dado nao encontrado");
        return (records[_dataHash].owner, records[_dataHash].timestamp);
    }
}
